class Solution {
public:
    int numberOfStableArrays(int zero, int one, int limit) {
        const int MOD = 1e9 + 7;
        int n = zero + one;
        vector<vector<vector<int>>> dp(n + 1, vector<vector<int>>(one + 1, vector<int>(limit + 1, 0)));
        dp[0][0][0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j <= one; j++) {
                for (int k = 0; k <= limit; k++) {
                    if (k == limit) continue;
                    if (j > 0) dp[i][j][k + 1] = (dp[i][j][k + 1] + dp[i - 1][j - 1][0]) % MOD;
                    if (zero > 0) dp[i][j][k + 1] = (dp[i][j][k + 1] + dp[i - 1][j][0] * (zero - (i - j - 1))) % MOD;
                }
            }
        }
        int res = 0;
        for (int k = 0; k <= limit; k++) {
            res = (res + dp[n][one][k]) % MOD;
        }
        return res;
    }
};
